// Limits a function to at most one execution per `wait` ms.
// Use for: scroll handlers, resize listeners, real-time search inputs.
export function throttle(fn, wait) {
    let lastCall = 0;
    return (...args) => {
        const now = Date.now();
        if (now - lastCall >= wait) {
            lastCall = now;
            fn(...args);
        }
    };
}
